import { useMap } from '@vis.gl/react-maplibre';
import { isNil, isUndefined } from 'lodash-es';
import type { MapLayerMouseEvent } from 'maplibre-gl';
import { useCallback, useEffect } from 'react';

import { BASE_LAYER_IDS } from '../constants.js';
import { getMinValueFeature } from '../utils/get-min-value-feature.js';

export const useActiveInteraction = () => {
  // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
  const map = useMap().current!;

  let featureId: string | number | undefined;
  let sourceId: string | undefined;

  const handleClick = useCallback(
    ({ point }: MapLayerMouseEvent) => {
      const features = map.queryRenderedFeatures(point);
      const allFeatures = map.queryRenderedFeatures();

      const layerId = features?.[0]?.layer?.id;

      const hasHoveredFeatures =
        !isNil(features) && features.length > 0 && !isUndefined(layerId);
      const isBaseLayer = BASE_LAYER_IDS.includes(layerId);

      if (hasHoveredFeatures && !isBaseLayer) {
        if (!isUndefined(featureId) && !isUndefined(sourceId)) {
          // if there's already an active feature, remove the active state
          map.setFeatureState(
            { source: sourceId, id: featureId },
            { active: false },
          );
        }

        const minFeature = getMinValueFeature(features);

        featureId = minFeature.id;
        sourceId = minFeature.layer.source;
        const activeState = features[0].state.active;

        // add the active state to the closest feature
        map.setFeatureState(
          { source: sourceId, id: featureId },
          { active: !activeState },
        );
        allFeatures.forEach((feature) => {
          if (feature.id !== undefined && feature.layer.source !== undefined) {
            map.setFeatureState(
              { source: feature.layer.source, id: feature.id },
              { isAnyActive: !activeState },
            );
          }
        }); //TODO: change to inactive
      } else {
        if (!isUndefined(featureId) && !isUndefined(sourceId)) {
          // remove the active state from the last active feature
          map.setFeatureState(
            { source: sourceId, id: featureId },
            { active: false },
          );
          allFeatures.forEach((feature) => {
            if (
              feature.id !== undefined &&
              feature.layer.source !== undefined
            ) {
              map.setFeatureState(
                { source: feature.layer.source, id: feature.id },
                { isAnyActive: false },
              );
            }
          });
        }
      }
    },
    [featureId, sourceId, map],
  );

  const onEscapeKeyPressedHandler = useCallback(
    (event: KeyboardEvent) => {
      if (event.key === 'Escape') {
        if (!isUndefined(featureId) && !isUndefined(sourceId)) {
          map.setFeatureState(
            { source: sourceId, id: featureId },
            { active: false },
          );

          const allFeatures = map.queryRenderedFeatures();
          allFeatures.forEach((feature) => {
            if (
              feature.id !== undefined &&
              feature.layer.source !== undefined
            ) {
              map.setFeatureState(
                { source: feature.layer.source, id: feature.id },
                { isAnyActive: false },
              );
            }
          });
        }
      }
    },
    [featureId, sourceId, map],
  );

  useEffect(() => {
    map.on('click', handleClick);
    window.addEventListener('keyup', onEscapeKeyPressedHandler);
    return () => {
      map.off('click', handleClick);
      window.removeEventListener('keyup', onEscapeKeyPressedHandler);
    };
  }, []);
};
